### Load possession data


::: {.cell}

```{.r .cell-code}
library(rlang)
library(cbbplotR)

# this data is from betiq from teamrankings 
# https://betiq.teamrankings.com/college-basketball/betting-trends/custom-trend-tool/?select_team=N+Carolina&select_opp=Duke
duke_unc <- readr::read_csv("duke-unc-ps.csv") |> 
  dplyr::filter(spread > 9.5) |> 
  dplyr::mutate(
        date = format(lubridate::mdy(date), "%B %d, %Y"),
        score = dplyr::if_else(
            unc_score > duke_score, 
            paste0("UNC ", unc_score, ", Duke ", duke_score),
            paste0("Duke ", duke_score, ", UNC ", unc_score)
        ),
        location = dplyr::case_when(
            location == "Away" ~ "Cameron Indoor Stadium",
            location == "Neutral" & spread == 26.0 ~ "Charlotte Coliseum",
            location == "Neutral" & spread == 12.0 ~ "Charlotte Coliseum",
            location == "Home" ~ "Dean E. Smith Center",
            TRUE ~ location
        )
    ) |> 
    cbbplotR::gt_cbb_teams(winner, winner, include_name = FALSE) |> 
    dplyr::select(date, winner, score, location, spread, unc_cover)
```
:::


