### Point spread table


::: {.cell}

```{.r .cell-code}
custom_header <- glue::glue(
  "<div style='display: flex; justify-content: space-between; align-items: center;'>
      <div>
       <img src='https://a.espncdn.com/combiner/i?img=/i/teamlogos/ncaa/500/153.png'
       style='height: 45px; width: auto; vertical-align: middle;'>
     </div>
     <div style='flex-grow:1; margin-left: 30px; margin-right: 30px'>
       <span style='display: block; font-weight: bold; text-align: center; font-size: 24px;'>North Carolina as a double-digit underdog against Duke</span>
       <span style='font-size: 12px; font-weight: normal; display: block; text-align: center;'>Since 1998, North Carolina is 9-5 against the spread with three outright wins as a double-digit underdog against Duke. The Blue Devils host UNC Saturday, and opened as a 13.5 point favorite per vegasinsider.com.</span>
     </div>
     <div>
       <img src='https://a.espncdn.com/combiner/i?img=/i/teamlogos/ncaa/500/150.png'
       style='height: 40px; width: auto; vertical-align: middle;'>
     </div>
   </div>
  <br>"
)

duke_tbl <- duke_unc |>
  dplyr::select(date, location, spread, unc_cover, score, winner) |>
  gt::gt() |>
  gtUtils::gt_theme_gtutils() |>
  gtExtras::gt_merge_stack(
    col1 = date,
    col2 = location,
    palette = c("black", "#707070")
  ) |>
  gt::fmt_markdown(winner) |>
  gt::fmt_tf(
    columns = unc_cover,
    tf_style = "check-mark",
    colors = c("#56a0d3", "#003087"),
  ) |>
  gt::fmt(
    columns = c(spread),
    fns = function(x) {
      ifelse(x > 0, paste0("+", x), x)
    }
  ) |>
  gtUtils::gt_column_subheaders(
    date = list(heading = "Date", subtitle = "Location"),
    winner = list(heading = "Winner", subtitle = "Outright"),
    score = list(heading = "Score", subtitle = "Final"),
    spread = list(heading = "Spread", subtitle = "UNC as Underdog"),
    unc_cover = list(heading = "Cover?", subtitle = "UNC"),
    heading_color = "black",
    subtitle_color = "gray"
  ) |>
  gt::tab_header(title = gt::html(custom_header)) |>
  gt::tab_source_note(
    source_note =
      gt::html(
        "<hr>Data via TeamRankings.com's BetIQ tool, theme via {gtUtils} and logos from ESPN.<hr><b>Table by Chris at Bless your chart</b>"
      )
  ) |>
  gtUtils::gt_border_bars_bottom(c("#56a0d3", "#89BDE0", "#BBD9ED")) |>
  gt::tab_options(table.width = gt::px(550)) |>
  gtUtils::gt_border_grid(color = "black",
                          weight = 1,
                          include_labels = FALSE) |>
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(11.5),
      weight = 250
    )
  ) |>
  gt::tab_style(
    style = list(gt::cell_text(font = gt::google_font("Signika Negative"))),
    locations = gt::cells_body(columns = everything())
  ) |>
  gt::cols_align(columns = c(winner, spread), align = "right") |>
  gt::cols_align(columns = c(date, score, unc_cover), align = "left") |>
  gtExtras::gt_highlight_rows(rows = c(8, 13, 14), fill = "#d0e4f3") |>
  gt::tab_style(
    style = list(gt::cell_text(
      font = gt::google_font("Signika Negative"),
      color = "#003087"
    )),
    locations = gt::cells_body(columns = c(score), rows = c(1:7, 9:11))
  ) |>
  gt::tab_style(style = list(gt::cell_text(
    font = gt::google_font("Signika Negative"),
    color = "#56a0d3"
  )),
  locations = gt::cells_body(columns = c(spread)))


gtUtils::gt_save_crop(duke_tbl,
                      file = "duke_unc.png",
                      whitespace = 60,
                      bg = "#FFFDF5")

duke_tbl
