run_header <- glue::glue(
  "<div style='display: flex; justify-content: space-between; align-items: center;'>
      <div>
       <img src='https://a.espncdn.com/combiner/i?img=/i/teamlogos/ncaa/500/153.png'
       style='height: 45px; width: auto; vertical-align: middle;'>
     </div>
     <div style='flex-grow:1; margin-left: 30px; margin-right: 30px'>
       <span style='display: block; font-weight: bold; text-align: center; font-size: 24px;'>North Carolina: Scoring Spurts by Opponent</span>
       <span style='font-size: 14px; font-weight: normal; display: block; text-align: center;'>Shows scoring runs of 6+ points or more in a given game. <br>Carolina is 13-9 overall and 6-4 in the ACC through January 28 games.</span>
     </div>
     <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-basketball.png'
       style='height: 40px; width: auto; vertical-align: middle;'>
     </div>
   </div>
  <br>"
)

run_tbl <- run_data |>
  cbbplotR::gt_cbb_teams(opponent, opponent) |>
  gt::gt() |>
  gt::cols_hide(run_diff) |>
  gtUtils::gt_theme_gtutils() |>
  gt::fmt_markdown(opponent) |>
  gt::fmt(
    columns = c(point_diff),
    fns = function(x) {
      ifelse(x > 0, paste0("+", x), x)
    }
  ) |>
  gtUtils::gt_column_subheaders(
    opp_n_runs = list(heading = "#", subtitle = "6+ points"),
    opp_avg_run_length = list(heading = "Avg", subtitle = "Points"),
    opp_total_run_points = list(heading = "Total", subtitle = "From spurts"),
    point_diff = list(heading = "+/-", subtitle = "From Runs"),
    unc_n_runs = list(heading = "#", subtitle = "6+ points"),
    unc_avg_run_length = list(heading = "Avg", subtitle = "Points"),
    unc_total_run_points = list(heading = "Total", subtitle = "From spurts"),
    heading_color = "black",
    subtitle_color = "gray"
  ) |>
  gt::tab_header(title = gt::html(run_header)) |>
  gt::tab_source_note(
    source_note =
      gt::html(
        "<hr>Data via bigballR + theme via {gtUtils} and logos from ESPN.<hr><b>Table by Chris at Bless your chart | data through January 28 games</b>"
      )
  ) |>
  gt::tab_spanner(label = "Opponent Spurts", columns = starts_with("opp_")) |>
  gt::tab_spanner(label = "UNC Spurts", columns = starts_with("unc_")) |>
  gt::fmt_number(columns = c(unc_avg_run_length, opp_avg_run_length),
                 decimals = 1) |>
  gt::data_color(columns = c(point_diff),
                 colors = scales::col_bin(
                   bins = c(-Inf, 0, Inf),
                   palette = c("#ffe7e7", "#d0e4f3")
                 )) |>
  gtUtils::gt_border_bars_bottom(c("#56a0d3", "#89BDE0", "#BBD9ED")) |>
  gt::tab_options(table.width = gt::px(675)) |>
  gtUtils::gt_border_grid(color = "black",
                          weight = 0.5,
                          include_labels = FALSE) |>
  gtExtras::gt_add_divider(columns = point_diff,
                           sides = "left",
                           color = "black") |>
  gtExtras::gt_add_divider(columns = point_diff,
                           sides = "right",
                           color = "black") |>
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(11.5),
      weight = 250
    )
  ) |>
  gt::tab_style(
    style = list(gt::cell_text(font = gt::google_font("Signika Negative"))),
    locations = gt::cells_body(columns = everything())
  ) |>
  gt::tab_style(
    locations = gt::cells_column_spanners(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      weight = 850,
      size = gt::px(15)
    )
  ) |>
  gt::cols_align(columns = c(opponent), align = "left") |>
  gt::cols_label(opponent = "") |>
  gtExtras::gt_highlight_rows( # this is silly 
    rows = c(1, 8, 9, 10, 11, 12, 15, 16, 17, 18, 19, 21, 22),
    columns = c(opponent),
    fill = "#d0e4f3"
  ) |>
  gtExtras::gt_highlight_rows(
    rows = c(2:7, 13, 14, 20),
    columns = c(opponent),
    fill = "#ffe7e7"
  )

gtUtils::gt_save_crop(run_tbl,
                      file = "run_unc.png",
