# save as csv 
# write.csv(duke_ht, "duke_ht.csv")

# load data
duke_ht <- readr::read_csv("duke_ht.csv")

# add theme 
theme_me <- function() {
  # Create a base theme with minimal style
  base_theme <- ggplot2::theme_minimal(base_size = 10, base_family = "RobotoCondensed-Regular")

  # Customize the base theme with additional modifications
  custom_theme <- base_theme +
    ggplot2::theme(
      plot.title = ggplot2::element_text(
        hjust = 0.5,
        size = 24,
        face = "bold"
      ),
      plot.subtitle = ggplot2::element_text(
        hjust = 0.5,
        size = 10,
        lineheight = 0.25,
        vjust = -0.5
      ),
      plot.caption = ggplot2::element_text(
        hjust = 1,
        size = 6,
        lineheight = 0.35,
        margin = ggplot2::margin(t = 20)
      ),
      plot.background = ggplot2::element_rect(fill = "floralwhite", color = "floralwhite")
    )

  return(custom_theme)
}

# make the plot
duke_is_tall <- duke_ht |>
  ggplot2::ggplot(ggplot2::aes(x = size, y = sizerk)) +
  ggplot2::geom_point(
    color = "#acacac",
    fill = "#c4ced4",
    shape = 21,
    size = 1,
    alpha = .75
  ) +
  ggplot2::scale_x_continuous(limits = c(74, 80), breaks = seq(74, 80, 1)) +
  ggplot2::scale_y_reverse(
    limits = c(370, 1),
    breaks = c(370, 300, 200, 100, 1),
    labels = c("Shortest", "300", "200", "100", "Tallest")
  ) +
  ggplot2::annotate(
    cfbplotR::GeomCFBlogo,
    x = 76.28,
    y = 322,
    team = "North Carolina",
    height = .10,
    alpha = .7
  ) +
  ggplot2::annotate(
    cfbplotR::GeomCFBlogo,
    x = 79.73,
    y = 1,
    team = "Duke",
    height = .10,
    alpha = .7
  ) +
  theme_me() +
  ggplot2::theme(
    plot.title = ggtext::element_markdown(
      size = 18,
      face = 'bold',
      family = 'mono'
    ),
    plot.subtitle = ggtext::element_markdown(
      size = 10,
      family = "mono",
      face = "bold"
    ),
    plot.caption = ggtext::element_markdown(size = 7, family = 'mono'),
